{
  "name": "get_order",
  "description": "Retrieve order details by order id.",
  "parameters": {
    "type": "object",
    "properties": {
      "order_id": {
        "type": "string",
        "pattern": "^ORD-[0-9]{4}-[A-Z0-9]+$",
        "description": "Order id in format ORD-YYYY-ALPHANUMERIC, e.g. ORD-2024-ABC123"
      }
    },
    "required": [
      "order_id"
    ]
  }
}
